-- Update Startseite service-cards block: show deliverable names instead of "3 Deliverables"
UPDATE cms_blocks
SET content = '{"sectionTitle":"Was Sie konkret erhalten","sectionSubtitle":"Jedes Modul liefert definierte Ergebnisse – keine vagen Empfehlungen, sondern Dokumente, Systeme und Prozesse, die direkt einsetzbar sind.","columns":3,"items":[{"badge":"A1","title":"KI-Quick-Start & Potenzialanalyse","href":"/ki-beratung/a1-ki-quick-start-potenzialanalyse","deliverables":[{"label":"Use-Case-Backlog","color":"purple"},{"label":"KI-Roadmap","color":"purple"},{"label":"Leitplanken (Guardrails)","color":"purple"}]},{"badge":"A2","title":"KI-Implementierung – Automationen & Workflows","href":"/ki-beratung/a2-ki-implementierung-automationen-workflows","deliverables":[{"label":"Laufende Automationen","color":"purple"},{"label":"Testprotokolle","color":"purple"},{"label":"Nutzerdokumentation","color":"purple"}]},{"badge":"A3","title":"KI-Assistenten & Chatbots","href":"/ki-beratung/a3-ki-assistenten-chatbots","deliverables":[{"label":"Bot-Setup + Blueprint","color":"purple"},{"label":"Gesprächsleitfäden","color":"purple"},{"label":"KPI-Set","color":"purple"}]},{"badge":"A4","title":"Prompting, Templates & Governance","href":"/ki-beratung/a4-prompting-templates-governance","deliverables":[{"label":"Prompt-Playbook","color":"purple"},{"label":"Governance-Kit","color":"purple"}]},{"badge":"A5","title":"KI-Schulungen & Enablement","href":"/ki-beratung/a5-ki-schulungen-enablement","deliverables":[{"label":"Schulungsunterlagen","color":"purple"},{"label":"Checklisten","color":"purple"}]},{"badge":"B1","title":"IT-Assessment & Stabilitätscheck","href":"/it-beratung/b1-it-assessment-stabilitaetscheck","deliverables":[{"label":"IT-Health-Report","color":"blue"},{"label":"Maßnahmenplan","color":"blue"}]},{"badge":"B2","title":"IT-Architektur & Modernisierung","href":"/it-beratung/b2-it-architektur-modernisierung","deliverables":[{"label":"Zielbild + Diagramme","color":"blue"},{"label":"Migrations-Roadmap","color":"blue"},{"label":"Runbooks","color":"blue"}]},{"badge":"B3","title":"Systemintegration & Prozess-IT","href":"/it-beratung/b3-systemintegration-prozess-it","deliverables":[{"label":"Integrierte Prozesse","color":"blue"},{"label":"Betriebs-/Nutzerdoku","color":"blue"}]},{"badge":"B4","title":"Betrieb, Monitoring & Dokumentation","href":"/it-beratung/b4-betrieb-monitoring-dokumentation","deliverables":[{"label":"Monitoring-Plan","color":"blue"},{"label":"Runbooks","color":"blue"},{"label":"Wiederanlaufplan","color":"blue"}]},{"badge":"B5","title":"IT-Standardisierung & Arbeitsplatz-IT","href":"/it-beratung/b5-it-standardisierung-arbeitsplatz-it","deliverables":[{"label":"Standardkonzept","color":"blue"},{"label":"On-/Offboarding-Prozess","color":"blue"}]},{"badge":"C1","title":"Security Quick Check","href":"/cybersecurity/c1-security-quick-check","deliverables":[{"label":"Risiko-Heatmap","color":"green"},{"label":"Maßnahmenkatalog","color":"green"},{"label":"Sofortmaßnahmenliste","color":"green"}]},{"badge":"C2","title":"Hardening & Sicherheitsbaselines","href":"/cybersecurity/c2-hardening-sicherheitsbaselines","deliverables":[{"label":"Baseline-Konzept","color":"green"},{"label":"Änderungsdokumentation","color":"green"}]},{"badge":"C3","title":"Backup, Recovery & Ransomware-Resilienz","href":"/cybersecurity/c3-backup-recovery-ransomware-resilienz","deliverables":[{"label":"Backup-/Recovery-Konzept","color":"green"},{"label":"Restore-Testprotokolle","color":"green"},{"label":"Wiederanlaufplan","color":"green"}]},{"badge":"C4","title":"Incident Response & Playbooks","href":"/cybersecurity/c4-incident-response-playbooks","deliverables":[{"label":"IR-Handbuch","color":"green"},{"label":"Playbook-Sammlung","color":"green"}]},{"badge":"C5","title":"Security Awareness & Phishing-Schutz","href":"/cybersecurity/c5-security-awareness-phishing-schutz","deliverables":[{"label":"Schulungsunterlagen","color":"green"},{"label":"Sicherheitsregeln","color":"green"}]},{"badge":"C6","title":"Datenschutz- & Compliance-Unterstützung","href":"/cybersecurity/c6-datenschutz-compliance-unterstuetzung","deliverables":[{"label":"TOM-Umsetzungsnachweis","color":"green"},{"label":"Audit-Dokumentationspaket","color":"green"}]}]}'::jsonb,
    updated_at = now()
WHERE page_id = (SELECT id FROM cms_pages WHERE slug = '/' LIMIT 1)
  AND block_type = 'service-cards'
  AND sort_order = 3;

-- Rebuild published_blocks for startseite
UPDATE cms_pages p
SET published_blocks = (
  SELECT jsonb_agg(
    jsonb_build_object('id', b.id, 'blockType', b.block_type, 'sortOrder', b.sort_order,
      'content', b.content, 'settings', b.settings, 'isVisible', b.is_visible)
    ORDER BY b.sort_order
  ) FROM cms_blocks b WHERE b.page_id = p.id
), has_draft_changes = false, updated_at = now()
WHERE p.slug = '/';
